const v11ReadA={id:"v11-read-a",kind:"passage",label:"Passage for Items 69-72",title:"Night Market Waste Trial",description:"A night market placed one large waste bin at each entrance, but cleaners still found mixed food scraps, bottles, and packaging throughout the aisles. During a four-week trial, organizers placed paired food-waste and recyclable bins beside every eating area and used picture labels showing common items sold at the market. Segregation improved near staffed areas but remained poor near the far exit. Organizers then rotated two volunteers through the exit during peak hours and moved the nearest bin into a brighter location. Contamination fell there as well. Because volunteer coverage was costly, the next trial would test whether lighting and clearer placement could sustain the result with fewer staff hours.",alt:"Passage about a night market improving waste segregation with paired picture-labeled bins, then volunteers and brighter bin placement at a poorly performing exit, followed by a planned test using fewer staff hours."};
const v11ReadB={id:"v11-read-b",kind:"passage",label:"Babasahin para sa Aytem 73-76",title:"Pila sa Botika ng Bayan",description:"Dalawang pila ang botika ng bayan: isa para sa bagong reseta at isa para sa muling pagkuha ng dating gamot. Gayunman, maraming pasyente ang hindi malaman kung saan pipila dahil magkahawig ang mga karatula. Pinalitan ang mga ito ng malalaking simbolo at maiikling halimbawa. Nabawasan ang maling pagpila, ngunit nahirapan pa rin ang ilang nakatatanda sa pagbabasa. Naglagay ang botika ng kawani sa may pasukan sa unang dalawang oras ng umaga, kung kailan pinakamarami ang tao. Binalak ding tanungin ang mga pasyente kung alin sa simbolo, teksto, o personal na gabay ang pinakanakatulong sa kanila.",alt:"Teksto tungkol sa botikang may dalawang pila, nagpalit ng karatula gamit ang simbolo at halimbawa, nagdagdag ng kawani para sa matatandang nahihirapang bumasa, at nagplanong alamin kung aling gabay ang pinakamabisa."};
const v11ReadC={id:"v11-read-c",kind:"passage",label:"Passage for Items 77-80",title:"Shared Service Counter",description:"Three small municipal units each maintained a separate reception desk, although none received enough visitors to keep a receptionist busy all day. The units combined reception at one shared counter while retaining specialists inside each office. The shared receptionist logged the purpose of each visit and contacted the correct specialist. Visitors waited less for initial assistance, but specialists reported frequent interruptions for simple status inquiries. The units added a status screen that displayed claim numbers without names and updated it twice daily. Interruptions declined, but the units scheduled a privacy review before adding more information to the display.",alt:"Passage about three municipal units combining reception, then adding a claim-number status screen to reduce specialist interruptions while scheduling a privacy review before displaying more information."};
const v11DataA={id:"v11-data-a",kind:"table",label:"Table for Items 155-158",title:"School Meal Distribution",description:"Meals targeted, prepared, and served at four schools during one distribution day. Unit: meals.",headers:["School","Target","Prepared","Served"],rows:[["Maple",480,470,455],["Pine",420,430,418],["Cedar",500,490,472],["Acacia",360,365,360]],legend:["Prepared: meals ready for release","Served: meals actually received by learners"],alt:"Table in meals. Maple: target 480, prepared 470, served 455. Pine: 420, 430, 418. Cedar: 500, 490, 472. Acacia: 360, 365, 360."};
