const v11DataD={id:"v11-data-d",kind:"table",label:"Table for Items 167-170",title:"Solar Street-Lamp Inspection",description:"Solar lamps assigned, inspected, operational, and repaired in four zones. Unit: lamps.",headers:["Zone","Assigned","Inspected","Operational before repair","Repaired"],rows:[["A",75,72,60,8],["B",68,68,57,7],["C",82,78,66,9],["D",60,57,51,4]],legend:["Repaired lamps are added to operational-before-repair when estimating operational lamps after work","Uninspected lamps have unknown condition"],alt:"Zone A: 75 assigned, 72 inspected, 60 operational before repair, 8 repaired. B: 68, 68, 57, 7. C: 82, 78, 66, 9. D: 60, 57, 51, 4."};
